import{c as l,Z as o,Q as d,j as u,g as t,n as s,o as r,m as n,av as p}from"./chunks/framework.BPKcPtvA.js";const v=JSON.parse('{"title":"Become an issuer","description":"Register an Issuer account, open the Apply wizard, get auto-approved (testnet), and deploy your on-chain issuer stack.","frontmatter":{"title":"Become an issuer","description":"Register an Issuer account, open the Apply wizard, get auto-approved (testnet), and deploy your on-chain issuer stack."},"headers":[],"relativePath":"guide/issuer/become-issuer.md","filePath":"guide/issuer/become-issuer.md","lastUpdated":1780219678000}'),c={name:"guide/issuer/become-issuer.md"};function g(h,e,m,y,k,b){const a=o("TaskMeta"),i=o("ExpectedResult");return d(),u("div",null,[e[1]||(e[1]=t("h1",{id:"become-an-issuer",tabindex:"-1"},[s("Become an issuer "),t("a",{class:"header-anchor",href:"#become-an-issuer","aria-label":'Permalink to "Become an issuer"'},"​")],-1)),r(a,{time:"~3–5 min",role:"Issuer",needs:"An Issuer-role passkey account"}),e[2]||(e[2]=n('<blockquote><p><strong>What you&#39;ll do:</strong> sign in as an issuer, open the <strong>Apply</strong> wizard, get auto-approved (testnet), and deploy your full on-chain issuer stack.</p></blockquote><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">You need an Issuer-role account</p><p>Your role — <strong>Investor</strong> or <strong>Issuer</strong> — is chosen <strong>when you create the account</strong> and is fixed per passkey. An Investor passkey <strong>can&#39;t</strong> apply to become an issuer: there&#39;s no in-app role switch. If you only have an Investor account, <strong>create a new account and pick the Issuer role</strong> (Step 1 below). Gas is sponsored, so you don&#39;t need any ETH.</p></div><div class="tip custom-block"><p class="custom-block-title">Already an approved issuer?</p><p>Signing in lands you on <code>/tokens</code>, and the <strong>Apply</strong> item disappears from the sidebar — skip to <a href="/guide/issuer/issue-token">Issue a token</a>.</p></div><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li><strong>Create (or sign in with) an Issuer account.</strong> Open <a href="https://muhaven.app" target="_blank" rel="noreferrer">muhaven.app</a> → <strong>Launch App</strong>. On the login card, use the link at the bottom to switch to <strong>Create account</strong>, choose the <strong>Issuer</strong> role, name your passkey, and click <strong>Create Account</strong> — then approve with your device. (See <a href="/guide/investor/sign-in">I1 · Sign in</a> for the passkey details.)<div class="tip custom-block"><p class="custom-block-title">Wrong-role sign-in</p><p>If you try to sign in as the wrong role, MuHaven tells you <em>&quot;This passkey is registered as an Investor / an Issuer&quot;</em> and flips the selector for you — pick the matching role and sign in again.</p></div></li><li><strong>Open the Apply wizard.</strong> A brand-new issuer account lands on it automatically. Anytime before you&#39;re approved, you can also click the pulsing <strong>Apply</strong> item at the top of the sidebar (desktop) or top bar (mobile) — it only shows for unapproved issuers. (Direct URL: <code>/apply-issuer</code>.)</li><li>On <strong>Step 1 — Welcome + KYB</strong>, enter your <strong>Legal entity name</strong>, <strong>jurisdiction</strong>, and <strong>contact email</strong>, then click <strong>Submit application</strong>.<div class="tip custom-block"><p class="custom-block-title">Testnet KYB is auto-approved</p><p>On testnet your KYB application is <strong>auto-approved the moment you submit</strong> — there&#39;s no waiting on a reviewer.</p></div></li><li>Click <strong>Next</strong> through the token-basics and economics steps. These collect your token&#39;s details — they&#39;re covered in full in <a href="/guide/issuer/issue-token">Issue a token</a>.</li><li>On the review step, click <strong>Deploy issuer stack</strong> to start deployment.</li><li>Watch the live deploy rail. It streams ~10 on-chain steps — deploy token, deploy redemption queue, deploy treasury, deploy yield snapshot, wire pointers, authorize registries, configure oracle, and register the token — each moving from <strong>pending</strong> to <strong>mined</strong> (~30–60s each).</li><li>When the success card appears, follow its final prompt to publish your first NAV and unpause the token, via HavenBot or the <a href="/guide/issuer/tokens-dashboard">Tokens dashboard</a>.</li></ol><div class="tip custom-block"><p class="custom-block-title">The wizard resumes on refresh</p><p>If you reload mid-flow, the wizard picks up where you left off — your progress isn&#39;t lost.</p></div><h2 id="expected-result" tabindex="-1">Expected result <a class="header-anchor" href="#expected-result" aria-label="Permalink to &quot;Expected result&quot;">​</a></h2>',8)),r(i,null,{default:p(()=>[...e[0]||(e[0]=[s(" You see the ",-1),t("strong",null,"Issuer stack deployed",-1),s(" success card with an ",-1),t("em",null,"Arbiscan",-1),s(" link to the deployed token. ",-1)])]),_:1}),e[3]||(e[3]=n('<h2 id="if-something-goes-wrong" tabindex="-1">If something goes wrong <a class="header-anchor" href="#if-something-goes-wrong" aria-label="Permalink to &quot;If something goes wrong&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Fix</th></tr></thead><tbody><tr><td>There&#39;s no <strong>Apply</strong> item in the sidebar</td><td>You&#39;re signed in as an <strong>Investor</strong>. The role is fixed per passkey — create a new account and pick the <strong>Issuer</strong> role (Step 1).</td></tr><tr><td>Sign-in says the passkey is the wrong role</td><td>Expected — MuHaven flips the role selector to the registered role; pick it and sign in again.</td></tr><tr><td><code>/apply-issuer</code> redirects you to <code>/tokens</code></td><td>You&#39;re already an approved issuer — go straight to <a href="/guide/issuer/issue-token">Issue a token</a>.</td></tr><tr><td>A deploy step sits on <strong>pending</strong></td><td>On-chain steps take ~30–60s each; give it time. See <a href="/guide/troubleshooting#async-waits">async waits</a>.</td></tr><tr><td>You refreshed and lost your place</td><td>The wizard resumes automatically — reopen <code>/apply-issuer</code>.</td></tr></tbody></table><p>→ Next: <a href="/guide/issuer/issue-token">Issue a token</a></p>',3))])}const w=l(c,[["render",g]]);export{v as __pageData,w as default};
